import React, { useState, useEffect } from 'react';
import Tab from 'react-bootstrap/Tab';
import Tabs from 'react-bootstrap/Tabs';
import CustomSection from './CustomSection'; 

function CustomTab({ tabs }) {
  const [activeTab, setActiveTab] = useState(tabs[0].eventKey);
  const [forceShowAll, setForceShowAll] = useState(false); // Estado para forzar la visualización de todas las secciones

  const handleSelect = (key) => {
    setActiveTab(key);
    setForceShowAll(false); // Al cambiar de pestaña, dejamos de forzar la visualización de todas las secciones
  };

  const handleShowAll = () => {
    setForceShowAll(true); // Función para forzar la visualización de todas las secciones
  };

  // Manejar cambios en el tamaño de la ventana
  useEffect(() => {
    const handleResize = () => {
      // Forzar una actualización del componente cuando cambie el tamaño de la ventana
      setActiveTab(activeTab => activeTab); // Esto puede parecer redundante, pero fuerza una actualización
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <Tabs
      activeKey={activeTab}
      onSelect={handleSelect}
      id="custom-tab"
      className="mb-3"
      justify
    >
      {tabs.map(tab => (
        <Tab
          key={tab.eventKey}
          eventKey={tab.eventKey}
          title={tab.title}
          disabled={tab.disabled}
        >
          {/* Renderizamos las secciones */}
          {Array.isArray(tab.content) ? (
            tab.content.map((content, index) => (
              <CustomSection
                key={index}
                forceShow={activeTab === tab.eventKey || forceShowAll} // Forzamos la visualización si la pestaña es la activa o se ha activado la opción de mostrar todas
              >
                {content}
              </CustomSection>
            ))
          ) : (
            <CustomSection forceShow={activeTab === tab.eventKey || forceShowAll}>
              {tab.content}
            </CustomSection>
          )}
        </Tab>
      ))}
    </Tabs>
  );
}

export default CustomTab;
